#include <iostream>
#include <numeric>
#include <vector>

int main() {
    std::size_t count{};
    if (!(std::cin >> count) || count > 100) return 1;
    std::vector<long long> values(count);
    for (auto& value : values) if (!(std::cin >> value)) return 1;
    long long sum = count < 3 ? 0 : std::accumulate(values.begin() + 1, values.end() - 1, 0LL);
    std::cout << sum << '\n';
}
